import { MakeLogicType, actions, afterMount, kea, path } from 'kea'
import { loaders } from 'kea-loaders'
import { router } from 'kea-router'

import api from 'lib/api'


// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface unsubscribeLogicValues {
    unsubscription: boolean;
    unsubscriptionLoading: boolean;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface unsubscribeLogicActions {
    attemptUnsubscribe: (token: string) => {
        token: string;
    };
    attemptUnsubscribeFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    attemptUnsubscribeSuccess: (unsubscription: boolean, payload?: {
        token: string;
    }) => {
        unsubscription: boolean;
        payload?: {
            token: string;
        };
    };
}

export type unsubscribeLogicType = MakeLogicType<unsubscribeLogicValues, unsubscribeLogicActions>;

export const unsubscribeLogic = kea<unsubscribeLogicType>([
    path(['scenes', 'Unsubscribe', 'unsubscribeLogic']),
    actions({
        attemptUnsubscribe: (token: string) => ({ token }),
    }),

    loaders(() => ({
        unsubscription: {
            __default: false as boolean,
            attemptUnsubscribe: async ({ token }) => {
                const res = await api.get(`api/unsubscribe?token=${token}`)
                return res.success
            },
        },
    })),
    afterMount(({ actions }) => {
        const { token } = router.values.searchParams
        actions.attemptUnsubscribe(token)
    }),
])
